import React from "react";
import { Navbar } from "flowbite-react";
import { Link } from "react-router-dom";

const Header = () => {
  return (
    <div>
      <Navbar fluid rounded>
        <Link to="/">
        <span className="">Movie Channel</span>
        </Link>
        </Navbar> </div> );
};

export default Header;
